function [UEs, carrier, info] = hCreateUsers(userConfig, enb)

% 初始化输出参数
UEs = [];
carrier = [];
info = struct;

% 从用户配置中获取参数
NUserNum = userConfig.NUserNum;
pwr_dbm = userConfig.pwr_dbm;
model = userConfig.Model;
seed = userConfig.seed;

% 根据模型生成用户分布和速度分布
switch model
    case 'Example'
        % 生成区域内随机分布的用户
        pos = hRandomUserPosition('UserDensity', 500, ...
            'AreaHeight', 5000, 'AreaWidth', 5000, ...
            'Seed', seed);
        speed = repmat(15, NUserNum, 1); % 所有用户速度都为15km/h
    case 'Random'
        % TODO：实现用户随机分布模型
    case 'City'
        % TODO：实现城市街区模型
    otherwise
        error('Unknown user distribution model.');
end

% 初始化每个用户的参数
UEs(NUserNum, 1) = struct;
for i = 1 : NUserNum
    UEs(i).Pwr_dBm = pwr_dbm;
    UEs(i).Pos = pos(i,:);
    UEs(i).Speed = speed(i,1);
end

% 初始化载波配置参数
carrier.Enb = enb;
carrier.Freq = lteDLFrequencyInfo(enb, 0); % 使用子帧0的频域资源
carrier.DuplexMode = enb.DuplexMode;
switch carrier.DuplexMode
    case 'FDD'
        carrier.TDDConfig = [];
    case 'TDD'
        carrier.TDDConfig = enb.TDDConfig;
    otherwise
        error('Unknown duplexing mode.');
end

% 返回一些有用的仿真信息
info.UserConfig = userConfig;
info.CellConfig = enb;
info.Model = model;

end

function [sinr_dB, rxPwr_dBm] = hUplinkSinr(carrier, UE)

% 计算用户与基站之间的距离
dist = sqrt(sum((UE.Pos - [carrier.Enb.Latitude, carrier.Enb.Longitude]).^2));

% 计算接收功率
if strcmp(carrier.DuplexMode, 'FDD')
    txPwrWatts = 10.^(UE.Pwr_dBm/10) / 1000;
    rxPwrWatts = 1 / ( 4 * pi * dist^2 ) * txPwrWatts;
    rxPwr_dBm = 10 * log10(rxPwrWatts * 1000);
else
    % 如果是TDD模式，需要考虑时隙配置
    switch carrier.TDDConfig
        case 0
            txPwrWatts = 10.^(UE.Pwr_dBm/10) / 1000;
            rxPwrWatts = 1 / ( 4 * pi * dist^2 ) * txPwrWatts;
            rxPwr_dBm = 10 * log10(rxPwrWatts * 1000);
        otherwise
            % TODO：实现TDD模式的接收功率计算方法
            error('Not implemented yet.')
    end
end

% 计算用户之间的相互干扰
I = 0;
for i = 1 : numel(carrier.UEs)
    if i == UE.NUserIdx % 排除自己对自己的干扰
        continue;
    end
    dist_ij = norm(UE.Pos - carrier.UEs(i).Pos); % 用户i与用户j之间的距离
    if dist_ij < carrier.Enb.CoverageArea[1]
        txPowerWatts = 10.^(carrier.UEs(i).Pwr_dBm/10) / 1000;
        I = I + 1 / ( 4 * pi * dist_ij^2 ) * txPowerWatts;
    end
end

% 计算信噪比
N_FFT = carrier.Enb.NDLRB * 12;
n_SC_offset = lteSCFDMAModulate(carrier.Enb, [0;1], 0);
bw_scale = N_FFT / numel(n_SC_offset);
N_0 = 10^(carrier.Enb.ReceivedNoiseFigure / 10) ...
    * carrier.Enb.Temperature * bw_scale;
sinr = rxPwrWatts / (N_0 + I);
sinr_dB = 10 * log10(sinr);

end

function pos = hRandomUserPosition(UserDensity, AreaHeight, AreaWidth, Seed)

% 计算仿真区域的面积和用户个数
Area = AreaHeight * AreaWidth / 1e6; % 将面积单位转换为平方千米
NUserNum = round(Area * UserDensity);

% 生成随机数
rng(Seed); % 设置随机数种子
x = rand(NUserNum,1) * AreaWidth;
y = rand(NUserNum,1) * AreaHeight;

% 按照列向量合并坐标
pos = [x, y];

end

结构体（struct）和双精度浮点数数组（double）是两种不同的数据类型，仅当结构体中的每个成员都是双精度浮点数时，才可以将结构体转换为双精度浮点数数组。在MATLAB中可以使用struct2array函数将结构体转换为数组，具体用法如下：

```matlab
myStruct.a = 1.2;
myStruct.b = 3.4;
myStruct.c = 5.6;

myArray = struct2array(myStruct);
```

上面的代码将结构体myStruct转换为双精度浮点数数组myArray，数组的值为[1.2 3.4 5.6]。如果结构体中有非数值类型的成员，struct2array函数将会报错。因此，在将结构体转换为数组时，需要确保结构体中的每个成员都是数值类型。

这个错误提示通常出现在试图将一个结构体（struct）直接赋值给一个双精度浮点数数组（double）时。例如：

```matlab
myStruct.a = 1.2;
myStruct.b = 3.4;
myStruct.c = 5.6;

myArray = myStruct; % 错误代码
```

在这个例子中，myStruct是一个结构体，myArray是一个双精度浮点数数组。直接将myStruct赋值给myArray是不合法的，因为这两个变量的数据类型不同。运行这段代码时，MATLAB会提示“无法从struct转换为double”。

如果想要将结构体中的数值属性转换为一个数组，可以使用struct2array函数，如下所示：

```matlab
myStruct.a = 1.2;
myStruct.b = 3.4;
myStruct.c = 5.6;

myArray = struct2array(myStruct); % 转换为数组
```

在这个例子中，调用了struct2array函数，将myStruct中的数值属性转换为一个数组myArray。这样就可以避免“无法从struct转换为double”的错误提示。
